typography.code_snippet:
/* Serif · 标题 & 大数字 */
--font-serif: "Noto Serif SC", "Source Han Serif SC",
             "Songti SC", serif;

/* Sans · 正文 & UI */
--font-sans: "Inter", "Noto Sans SC",
            "PingFang SC", sans-serif;

/* Mono · 代码 & 数据 */
--font-mono: "IBM Plex Mono", "SFMono-Regular",
            monospace;

spacing.code_snippet:
/* 间距标尺 (8px 基准) */
--space-2: 8px;
--space-3: 12px;
--space-4: 16px;
--card-padding: 24px;
--space-6: 32px;
--space-8: 48px;
--section-gap: 64px;

/* 布局约束 */
--content-width: 840px;
